    const threadIndex = Object.fromEntries(window.THREAD_DATA.map(thread => [thread.id, thread]));

    function appendReplies(threadId, replySpecs) {
        const thread = threadIndex[threadId];
        if (!thread || !replySpecs.length) return;
        const repliesToAdd = replySpecs.map(makePost);
        const nextReplyCount = String(Number(thread.replies || 0) + repliesToAdd.length);
        thread.replies = nextReplyCount;
        thread.lastUserHtml = replySpecs[replySpecs.length - 1].username;
        thread.lastDateHtml = "2007.XX.XX";
        thread.sectionHtml = thread.sectionHtml
            .replace(/(<b>Replies:<\/b>\s*)\d+/, `$1${nextReplyCount}`)
            .replace('<div class="back-top">', `${repliesToAdd.join("\n")}\n  <div class="back-top">`);
    }

